import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"46. Overtime","description":"","frontmatter":{"title":"46. Overtime","eba":"Biomedical Engineers 2025-2028","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/biomedical-engineers/hours-of-work/46-overtime.md","filePath":"ebas/biomedical-engineers/hours-of-work/46-overtime.md"}'),n={name:"ebas/biomedical-engineers/hours-of-work/46-overtime.md"};function i(s,e,l,p,h,m){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_46-overtime" tabindex="-1">46. Overtime <a class="header-anchor" href="#_46-overtime" aria-label="Permalink to &quot;46. Overtime&quot;">​</a></h1><p><strong>46.1</strong> General An Employer may require an Employee to work reasonable overtime and such Employee shall work overtime in accordance with such requirement.</p><p><strong>46.2</strong> Employee may refuse to work unreasonable overtime An Employee may refuse to work overtime hours where they are unreasonable. In determining whether overtime hours are reasonable or unreasonable, the following must be taken into account:</p><p><strong>(a)</strong> Any risk to Employee health and safety from working the additional hours;</p><p><strong>(b)</strong> The employee’s personal circumstances, including family responsibilities;</p><p><strong>(c)</strong> The needs of the workplace or enterprise in which the Employee is employed;</p><p><strong>(d)</strong> Whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, working additional hours</p><p><strong>(e)</strong> Any notice given by the Employer of any request or requirement to work the additional hours;</p><p><strong>(f)</strong> Any notice given by the Employee of their intention to refuse to work the additional hours;</p><p><strong>(g)</strong> The usual patterns of work in the industry, or the part of an industry, in which the Employee works;</p><p><strong>(h)</strong> The nature of the Employee’s role, and the Employee’s level of responsibility;</p><p><strong>(i)</strong> How frequently an Employee is required to perform overtime; and</p><p><strong>(j)</strong> Any other relevant matter.</p><p><strong>46.3</strong> Overtime - meaning For the purpose of this clause, in accruing or calculating payment of overtime, each period of overtime shall stand alone.</p><p><strong>(a)</strong> Only authorised overtime shall be paid for and the following rates of overtime shall apply: Other than the Royal Children’s Hospital and the Royal Women’s Hospital:</p><p><strong>(i)</strong> In excess of the ordinary hours of work on any one day – 150% for the first two hours and 200% thereafter;</p><p><strong>(ii)</strong> Outside the spread of twelve hours from the commencement of the last rostered period of ordinary time – 200%;</p><p><strong>(iii)</strong> On a Saturday or Sunday: in excess of the ordinary hours of work on any one day or in excess of the ordinary week’s work– 200%; The Royal Children’s Hospital and the Royal Women’s Hospital only:</p><p><strong>(iv)</strong> In excess of the ordinary hours of work on any one day – 150% for the first two hours and 200% thereafter; and</p><p><strong>(v)</strong> Outside the spread of nine hours from the commencement of the last rostered period of ordinary time – 150%, and</p><p><strong>(vi)</strong> Outside the spread of twelve hours from the commencement of the last rostered period of ordinary time – 200%.</p><p><strong>(vii)</strong> On a Saturday or Sunday: in excess of the ordinary hours of work on any one day or in excess of the ordinary week’s work– 200%;</p><p><strong>(b)</strong> In lieu of the above penalty rates, the following apply to casual Employees who perform overtime:</p><p><strong>(i)</strong> Monday to Saturday – 187.5% of the minimum hourly rate for the first 2 hours and 250% of the minimum hourly rate after 2 hours;</p><p><strong>(ii)</strong> Sundays and Public Holidays – 250% of the minimum hourly rate.</p><p><strong>(c)</strong> The following clause does not apply to Employees at Barwon Health, Latrobe Regional Health and Western Health Overtime shall be paid wherever work is performed in addition to the full-time rostered shift length for that work area. Where full time Employees in a particular work area work 8 hours per shift, overtime will be payable where a part time Employee in that same work area works beyond 8 hours in a shift. Where full time Employee work 10 hours per shift, overtime will be payable where a part-time Employee works beyond 10 hours.</p><p><strong>46.4</strong> Time in Lieu Except as provided for in subclauses 46.4(a) and 46.4(b) below, overtime shall be paid for and an Employee shall not be allowed to take time off in lieu thereof.</p><p><strong>(a)</strong> Other than the Royal Children’s Hospital and the Royal Women’s Hospital: An Employee who is classified as a Class 4 or 5 may elect, in lieu of payment of overtime, to take time off equivalent to the time worked at a time mutually agreed between the Employer and the Employee.</p><p><strong>(b)</strong> The Royal Children’s Hospital and the Royal Women’s Hospital only: An Employee may elect with the consent of the Employer to take time off in lieu of payment for overtime at a time or times agreed with the Employer. Overtime taken as time off in lieu of payment shall be taken at the ordinary time rate, and the Employer shall provide payment at the appropriate overtime rate as specified in this clause where time off in lieu has not been taken within 28 days of accrual.</p><p><strong>46.5</strong> Transport following overtime In the event of any Employee finishing any period of overtime at a time when reasonable means of transport are not available for the Employee to return to their place of residence the Employer shall provide adequate transport free of cost to the Employee.</p><p><strong>46.6</strong> Rest Break during overtime An Employee working overtime will take a paid rest break of 20 minutes after each four (4) hours of overtime worked if required to continue work after the break.</p><p>Plain language terms: OT, extra hours, double time.</p>',32)])])}const y=o(n,[["render",i]]);export{f as __pageData,y as default};
